import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider } from './context/AuthContext';
import ProtectedRoute from './components/Layout/ProtectedRoute';
import Navbar from './components/Layout/Navbar';
import Login from './components/Auth/Login';
import Register from './components/Auth/Register';
import ChangePassword from './components/Auth/ChangePassword';
import AdminDashboard from './components/Admin/Dashboard';
import UserList from './components/Admin/UserList';
import StoreList from './components/Admin/StoreList';
import AddUser from './components/Admin/AddUser';
import StoreListing from './components/User/StoreListing';
import OwnerDashboard from './components/StoreOwner/OwnerDashboard';

function App() {
  return (
    <Router>
      <AuthProvider>
        <Navbar />
        <Routes>
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />
          
          <Route path="/user/change-password" element={
            <ProtectedRoute allowedRoles={['user', 'owner']}>
              <ChangePassword />
            </ProtectedRoute>
          } />
          
          {/* Admin Routes */}
          <Route path="/admin/dashboard" element={
            <ProtectedRoute allowedRoles={['admin']}>
              <AdminDashboard />
            </ProtectedRoute>
          } />
          <Route path="/admin/users" element={
            <ProtectedRoute allowedRoles={['admin']}>
              <UserList />
            </ProtectedRoute>
          } />
          <Route path="/admin/stores" element={
            <ProtectedRoute allowedRoles={['admin']}>
              <StoreList />
            </ProtectedRoute>
          } />
          <Route path="/admin/add-user" element={
            <ProtectedRoute allowedRoles={['admin']}>
              <AddUser />
            </ProtectedRoute>
          } />
          
          {/* User Routes */}
          <Route path="/user/stores" element={
            <ProtectedRoute allowedRoles={['user']}>
              <StoreListing />
            </ProtectedRoute>
          } />
          
          {/* Owner Routes */}
          <Route path="/owner/dashboard" element={
            <ProtectedRoute allowedRoles={['owner']}>
              <OwnerDashboard />
            </ProtectedRoute>
          } />
          
          <Route path="/" element={<Navigate to="/login" />} />
        </Routes>
      </AuthProvider>
    </Router>
  );
}

export default App;
